# The race needs a yield point between read(seq/prev_hash) and append. The real code has
# clock()+digest()+freeze between them. Force interleaving with a clock that sleeps a hair,
# to prove the UNLOCKED path corrupts and the LOCKED path does not.
import datetime as dt, threading, time
from assay_engine.provenance import ProvenanceTrail, ProvenanceError

UTC = dt.timezone.utc
def slow_clock():
    time.sleep(0.0002)  # widen the read->append window, releasing the GIL
    return dt.datetime.now(tz=UTC)

class NullLock:
    def __enter__(self): return self
    def __exit__(self, *a): return False

def run(unlock):
    t = ProvenanceTrail(clock=slow_clock)
    if unlock: t._lock = NullLock()
    barrier = threading.Barrier(8)
    def worker(w):
        barrier.wait()
        for i in range(50):
            t.record("k", f"w{w}-{i}", w=w, i=i)
    ths = [threading.Thread(target=worker, args=(w,)) for w in range(8)]
    for th in ths: th.start()
    for th in ths: th.join()
    try:
        assert len(t) == 400, f"len={len(t)}"
        t.verify()
        assert [e.seq for e in t.entries] == list(range(400))
        return "OK"
    except (AssertionError, ProvenanceError) as e:
        return f"CORRUPTED: {e}"

print("UNLOCKED:", run(unlock=True))
print("LOCKED:  ", run(unlock=False))
EOF

